UPDATE users SET rub_mantissa = CAST(COALESCE(rub,0) AS CHAR), rub_exponent = 0 WHERE rub_mantissa IS NULL OR rub_mantissa = '' OR rub_exponent IS NULL OR (rub_mantissa = '0' AND COALESCE(rub,0) <> 0);
